def _surface_floor_rule(mm, i, j):
    if (1, i, j) not in mm.D:
        return Constraint.Skip
    return mm.x[1, i, j] >= 0.40
model.surface_floor = Constraint(model.I, model.J, rule=_surface_floor_rule)

def _corner_parity_rule(mm, l):
    if (l, 1, 1) not in mm.D or (l, 4, 4) not in mm.D:
        return Constraint.Skip
    return mm.x[l, 4, 4] >= 0.25 * mm.x[l, 1, 1]
model.corner_parity = Constraint(model.L, rule=_corner_parity_rule)

def _even_surface_rule(mm, i, j):
    if (1, i, j) not in mm.D:
        return Constraint.Skip
    return mm.x[1, i, j] >= 0.50
model.even_surface = Constraint(model.I, model.J, rule=_even_surface_rule)
